+
+    #[test]
+    fn canonical_sha256_convenience_works() {
+        let tmp = tempfile::TempDir::new().unwrap();
+        let db_path = tmp.path().join("test.db");
+
+        let conn = rusqlite::Connection::open(&db_path).unwrap();
